long long solve(vector<long long> landStartTime, vector<long long> landDuration, vector<long long> waterStartTime, vector<long long> waterDuration) {

    long long min_time = INF;

    int n = landStartTime.size();

    int m = waterStartTime.size();

    for (int i=0; i < n; ++i) {

        for (int j=0; j < m; ++j) {

            // 情况一：陆地先

            long long land_end = landStartTime[i] + landDuration[i];

            long long water_start = max(waterStartTime[j], land_end);

            long long water_end = water_start + waterDuration[j];

            long long case1 = water_end;

            // 情况二：水先

            long long water_end2 = waterStartTime[j] + waterDuration[j];

            long long land_start = max(landStartTime[i], water_end2);

            long long land_end2 = land_start + landDuration[i];

            long long case2 = land_end2;

            // 取这两个情况的最小值

            long long current_min = min(case1, case2);

            if (current_min < min_time) {

                min_time = current_min;

            }

        }

    }

    return min_time;

}

